/** Generates independently replayable W3C-target certificates across ten fixed release seeds. */
@Tag("slow")
class SpecificationCertificateCampaignTest {
	private static final List<Long> SEEDS = List.of(
			0x5905_1101L,
			0x5905_1102L,
			0x5905_1103L,
			0x5905_1104L,
			0x5905_1105L,
			0x5905_1106L,
			0x5905_1107L,
			0x5905_1108L,
			0x5905_1109L,
			0x5905_1110L);
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void generateW3cTargetCertificateCampaign() throws IOException {
		int pairsPerTarget = Integer.getInteger("equivalence.certification.specPairsPerTarget", 200);
		long timeBudgetSeconds = Long.getLong("equivalence.certification.specTimeBudgetSeconds", 3600L);
		Path outputDirectory = Path.of(System.getProperty(
				"equivalence.certification.specOutputDir",
				"target/certification/specification"));
		Files.createDirectories(outputDirectory);
		Path certificates = outputDirectory.resolve("certificates.jsonl");
		Path summary = outputDirectory.resolve("summary.csv");
		Instant started = Instant.now();
		Instant deadline = started.plusSeconds(timeBudgetSeconds);

		try (BufferedWriter certificateWriter = Files.newBufferedWriter(
				certificates,
				StandardCharsets.UTF_8,
				StandardOpenOption.CREATE,
				StandardOpenOption.TRUNCATE_EXISTING);
				BufferedWriter summaryWriter = Files.newBufferedWriter(
						summary,
						StandardCharsets.UTF_8,
						StandardOpenOption.CREATE,
						StandardOpenOption.TRUNCATE_EXISTING)) {
			summaryWriter.write("semanticsTarget,versionIri,seed,pairs\n");
			for (SemanticsTarget target : List.of(SemanticsTarget.SPARQL_1_1, SemanticsTarget.SPARQL_1_2_DRAFT)) {
				int generatedForTarget = 0;
				for (int seedIndex = 0; seedIndex < SEEDS.size(); seedIndex++) {
					long seed = SEEDS.get(seedIndex);
					int seedCount = pairsPerTarget / SEEDS.size()
							+ (seedIndex < pairsPerTarget % SEEDS.size() ? 1 : 0);
					for (int pairIndex = 0; pairIndex < seedCount; pairIndex++) {
						assertTrue(Instant.now().isBefore(deadline),
								"time budget truncated the W3C certificate campaign");
						long identity = mix(seed, pairIndex);
						CampaignPair pair = pair(target, identity, pairIndex);
						EquivalenceResult result = new AlgebraEquivalenceChecker(pair.options())
								.check(pair.original(), pair.candidate());
						assertEquals(EquivalenceStatus.EQUIVALENT, result.getStatus(), result::getReason);
						NormalizationProof proof = assertInstanceOf(
								NormalizationProof.class,
								result.getEvidence().orElseThrow());
						NormalizationCertificate certificate = proof.getCertificate().orElseThrow();
						assertTrue(new ProofKernel(pair.options()).verify(
								pair.original(), pair.candidate(), proof));
						assertEquals(target, certificate.getSemanticsTarget());
						certificateWriter.write(certificate.toJson());
						certificateWriter.newLine();
						generatedForTarget++;
					}
					summaryWriter.write(target + "," + target.getVersionIri().orElseThrow() + "," + seed + ","
							+ seedCount + "\n");
				}
				assertEquals(pairsPerTarget, generatedForTarget);
			}
			summaryWriter.write("TOTAL,,," + (2L * pairsPerTarget) + "\n");
			summaryWriter.write("ELAPSED_SECONDS,,," + Duration.between(started, Instant.now()).toSeconds() + "\n");
		}
	}

	private static CampaignPair pair(SemanticsTarget target, long identity, int pairIndex) {
		TupleExpr leaf = leaf(identity);
		ObservationMode observation = ObservationMode.BAG;
		ContextMode context = ContextMode.ALL_BINDINGS;
		TupleExpr original;
		TupleExpr candidate;
		switch (Math.floorMod(pairIndex, 17)) {
		case 0 -> {
			original = new Join(new SingletonSet(), leaf.clone());
			candidate = leaf;
		}
		case 1 -> {
			original = new Union(new EmptySet(), leaf.clone());
			candidate = leaf;
		}
		case 2 -> {
			original = new LeftJoin(new EmptySet(), leaf.clone());
			candidate = new EmptySet();
		}
		case 3 -> {
			original = new LeftJoin(leaf.clone(), new EmptySet());
			candidate = leaf;
		}
		case 4 -> {
			original = new LeftJoin(leaf.clone(), new SingletonSet());
			candidate = leaf;
		}
		case 5 -> {
			original = new Difference(new EmptySet(), leaf.clone());
			candidate = new EmptySet();
		}
		case 6 -> {
			original = new Difference(leaf.clone(), new EmptySet());
			candidate = leaf;
		}
		case 7 -> {
			observation = ObservationMode.SEQUENCE;
			original = new Filter(leaf.clone(), new ValueConstant(VF.createLiteral(true)));
			candidate = leaf;
		}
		case 8 -> {
			original = new Distinct(new Distinct(leaf.clone()));
			candidate = new Distinct(leaf);
		}
		case 9 -> {
			observation = ObservationMode.SET;
			original = new Union(leaf.clone(), leaf.clone());
			candidate = leaf;
		}
		case 10 -> {
			observation = ObservationMode.ASK;
			original = new Union(leaf.clone(), leaf.clone());
			candidate = leaf;
		}
		case 11 -> {
			observation = ObservationMode.SET;
			original = new Distinct(leaf.clone());
			candidate = leaf;
		}
		case 12 -> {
			observation = ObservationMode.ASK;
			original = new Distinct(leaf.clone());
			candidate = leaf;
		}
		case 13 -> {
			observation = ObservationMode.SET;
			original = new Reduced(leaf.clone());
			candidate = leaf;
		}
		case 14 -> {
			observation = ObservationMode.ASK;
			original = new Reduced(leaf.clone());
			candidate = leaf;
		}
		case 15 -> {
			original = values(false);
			candidate = new EmptySet();
		}
		default -> {
			context = ContextMode.TOP_LEVEL_EMPTY;
			original = values(true);
			candidate = new SingletonSet();
		}
		}
		CheckOptions options = CheckOptions.builder()
				.semanticsTarget(target)
				.observationMode(observation)
				.contextMode(context)
				.boundedCounterexampleSearch(false)
				.build();
		return new CampaignPair(original, candidate, options);
	}

	private static BindingSetAssignment values(boolean unit) {
		BindingSetAssignment values = new BindingSetAssignment();
		values.setBindingSets(unit ? List.of(new MapBindingSet()) : List.of());
		return values;
	}

	private static StatementPattern leaf(long identity) {
		IRI predicate = VF.createIRI("urn:rdf4j:equivalence:campaign:p" + Long.toUnsignedString(identity));
		return new StatementPattern(
				Var.of("s"),
				Var.of("p", predicate),
				Var.of("o" + Long.toUnsignedString(identity)));
	}

	private static long mix(long seed, int index) {
		long value = seed + 0x9E3779B97F4A7C15L * (index + 1L);
		value = (value ^ (value >>> 30)) * 0xBF58476D1CE4E5B9L;
		value = (value ^ (value >>> 27)) * 0x94D049BB133111EBL;
		return value ^ (value >>> 31);
	}

	private record CampaignPair(TupleExpr original, TupleExpr candidate, CheckOptions options) {
	}
}
